// Normaliza o payload do Typebot e define se é lead QUENTE (precisa Karine)
const body = $input.first().json.body || $input.first().json;

const evento = String(body.evento || 'desconhecido');
const quentes = ['quer_negociar', 'cpf_nao_localizado'];
const ehQuente = quentes.includes(evento);

return [{ json: {
  evento,
  ehQuente,
  cpf: String(body.cpf || '').replace(/\D/g, ''),
  nome: body.nome || 'Cliente',
  escolha: body.escolha || '',
  valor_divida: body.valor_divida || '',
  valor_a_vista_50: body.valor_a_vista_50 || '',
  origem: body.origem || 'typebot-quitacao-pd',
  data_iso: new Date().toISOString(),
  data_br: new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })
} }];

