// Monta a mensagem de alerta para a Karine conforme o evento
const row = $('Classificar Evento').first().json;

const textos = {
  quer_negociar: `🔥 LEAD QUENTE — Perdão de Dívida\n\n${row.nome} (CPF ${row.cpf}) escolheu *${row.escolha}*.\nDívida: R$ ${row.valor_divida} | À vista 50%: R$ ${row.valor_a_vista_50}\n\n👉 Chamar agora para fechar a condição.`,
  cpf_nao_localizado: `⚠️ Perdão de Dívida — CPF não localizado\n\nUm cliente tentou quitar mas o CPF ${row.cpf} não foi encontrado no Asaas.\n\n👉 Verificar cadastro (pode estar em outro nome) e chamar a pessoa.`
};

const texto = textos[row.evento] || `Evento ${row.evento} — ${row.nome} (${row.cpf})`;
return [{ json: { ...row, alerta: texto } }];
